import "./ReactorCard.css";

function ReactorCard({ title, status = "ONLINE", children, variant = "orange" }) {
  return (
    <div className={`reactor-card ${variant}`}>
      
      {/* Animated Border */}
      <div className="reactor-card-border"></div>

      {/* Energy Background */}
      <div className="reactor-card-core"></div>

      <div className="reactor-card-content">
        
        <div className="reactor-card-header">
          <h3>{title}</h3>
          <span className="reactor-status">{status}</span>
        </div>

        <div className="reactor-card-body">
          {children}
        </div>

      </div>
    </div>
  );
}

export default ReactorCard;

.reactor-card {
  position: relative;
  width: 340px;
  padding: 28px;
  border-radius: 22px;
  overflow: hidden;
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);

  background: rgba(255, 255, 255, 0.04);
  border: 1px solid rgba(255,255,255,0.12);

  transition: 0.4s ease;
}

/* ===================== */
/* ENERGY CORE BACKGROUND */
/* ===================== */

.reactor-card-core {
  position: absolute;
  width: 200px;
  height: 200px;
  top: -60px;
  right: -60px;
  border-radius: 50%;
  filter: blur(80px);
  opacity: 0.25;
  z-index: 0;
  animation: pulseCore 4s ease-in-out infinite;
}

/* ===================== */
/* ROTATING BORDER */
/* ===================== */

.reactor-card-border {
  position: absolute;
  inset: -1px;
  border-radius: 22px;
  padding: 1px;
  z-index: 0;
  animation: rotateBorder 8s linear infinite;
}

/* ===================== */
/* CONTENT */
/* ===================== */

.reactor-card-content {
  position: relative;
  z-index: 2;
}

.reactor-card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 18px;
}

.reactor-card-header h3 {
  font-size: 15px;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  font-weight: 600;
  opacity: 0.85;
}

.reactor-status {
  font-size: 11px;
  padding: 4px 10px;
  border-radius: 20px;
  backdrop-filter: blur(10px);
  background: rgba(255,255,255,0.08);
  letter-spacing: 1px;
}

.reactor-card-body {
  font-size: 14px;
  opacity: 0.75;
  line-height: 1.6;
}

/* ===================== */
/* HOVER */
/* ===================== */

.reactor-card:hover {
  box-shadow: 0 0 40px rgba(255,255,255,0.06);
}

.reactor-card:hover .reactor-card-core {
  opacity: 0.45;
}

/* ===================== */
/* VARIANTS */
/* ===================== */

.reactor-card.orange .reactor-card-core {
  background: #de732c;
}

.reactor-card.orange .reactor-card-border {
  background: linear-gradient(
    130deg,
    transparent,
    #de732c,
    transparent
  );
}

.reactor-card.blue .reactor-card-core {
  background: #126fff;
}

.reactor-card.blue .reactor-card-border {
  background: linear-gradient(
    130deg,
    transparent,
    #126fff,
    transparent
  );
}

.reactor-card.green .reactor-card-core {
  background: #176635;
}

.reactor-card.green .reactor-card-border {
  background: linear-gradient(
    130deg,
    transparent,
    #176635,
    transparent
  );
}

/* ===================== */
/* ANIMATIONS */
/* ===================== */

@keyframes rotateBorder {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

@keyframes pulseCore {
  0%, 100% {
    transform: scale(1);
  }
  50% {
    transform: scale(1.1);
  }
}
